import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const h=JSON.parse('{"title":"الدوال | Dotfiles (AR)","titleTemplate":":title","description":"دوال الشل التي تُحسّن تجربتك مع الطرفية. أدوات لاختبار API وإدارة الملفات وعمليات النظام والمزيد. متوافق مع macOS وLinux وWSL عبر Dotfiles.","frontmatter":{"title":"الدوال | Dotfiles","description":"دوال الشل التي تُحسّن تجربتك مع الطرفية. أدوات لاختبار API وإدارة الملفات وعمليات النظام والمزيد. متوافق مع macOS وLinux وWSL عبر Dotfiles.","lang":"ar-SA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"الدوال preview","canonical":"/ar/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"الدوال","pageType":"docs","schemaType":"WebPage","metaTitle":"الدوال - Dotfiles (AR)","permalink":"/ar/functions/","meta":[{"name":"keywords","content":"functions, shell, bash, zsh, dotfiles, productivity, utilities, api, file, system"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"دوال الشل التي تُحسّن تجربتك مع الطرفية. أدوات لاختبار API وإدارة الملفات وعمليات النظام والمزيد."},{"name":"twitter:title","content":"الدوال - Dotfiles"},{"name":"og:title","content":"الدوال - Dotfiles"},{"name":"og:description","content":"دوال الشل التي تُحسّن تجربتك مع الطرفية. أدوات لاختبار API وإدارة الملفات وعمليات النظام والمزيد."},{"name":"og:image:alt","content":"Dotfiles - مصمم ببساطة ليناسب حياتك مع الشل"},{"name":"og:locale","content":"ar_SA"}]},"headers":[],"relativePath":"ar/functions/index.md","filePath":"ar/functions/index.md","lastUpdated":1773010926000}'),i={name:"ar/functions/index.md"};function o(s,t,n,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="الدوال" tabindex="-1">الدوال <a class="header-anchor" href="#الدوال" aria-label="Permalink to &quot;الدوال&quot;">​</a></h1><p>أدوات شل لتعزيز إنتاجيتك عبر macOS وLinux وWindows.</p><h2 id="اكتشف" tabindex="-1">اكتشف <a class="header-anchor" href="#اكتشف" aria-label="Permalink to &quot;اكتشف&quot;">​</a></h2><p>الدوال معرّفة كملفات <code>.sh</code> فردية. أثناء <code>chezmoi apply</code>، تُجمّع في <code>~/.config/shell/functions.sh</code> ويتم تحميلها بواسطة الشل الخاص بك.</p><h2 id="ابدأ" tabindex="-1">ابدأ <a class="header-anchor" href="#ابدأ" aria-label="Permalink to &quot;ابدأ&quot;">​</a></h2><h3 id="إضافة-دالة" tabindex="-1">إضافة دالة <a class="header-anchor" href="#إضافة-دالة" aria-label="Permalink to &quot;إضافة دالة&quot;">​</a></h3><ol><li>أنشئ ملف <code>.sh</code> جديد (مثال: <code>myfunc.sh</code>)</li><li>أضف تعريف دالتك</li><li>طبّق التغييرات:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="المرجع" tabindex="-1">المرجع <a class="header-anchor" href="#المرجع" aria-label="Permalink to &quot;المرجع&quot;">​</a></h2><h3 id="اختبار-api" tabindex="-1">اختبار API <a class="header-anchor" href="#اختبار-api" aria-label="Permalink to &quot;اختبار API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">فحص صحة واحد أو أكثر من APIs</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">مراقبة زمن استجابة API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">إجراء اختبار حمل أساسي</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">تصحيح طلبات HTTP مع التوقيت</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="أدوات-http" tabindex="-1">أدوات HTTP <a class="header-anchor" href="#أدوات-http" aria-label="Permalink to &quot;أدوات HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">عرض رؤوس HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">فحص رمز حالة HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">قياس مقاييس توقيت HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">عرض الكود المصدري لموقع</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">إيجاد العملية التي تستخدم منفذًا</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="إدارة-الملفات" tabindex="-1">إدارة الملفات <a class="header-anchor" href="#إدارة-الملفات" aria-label="Permalink to &quot;إدارة الملفات&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">إنشاء نسخ احتياطية بطابع زمني</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">ترميز وفك ترميز Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">استخراج صيغ الأرشيف</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">عرض الملف بصيغة hex</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">إعادة تسمية الامتدادات بالجملة</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">فحص حجم ملف أو مجلد</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">إنشاء أرشيفات ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="تسمية-الملفات" tabindex="-1">تسمية الملفات <a class="header-anchor" href="#تسمية-الملفات" aria-label="Permalink to &quot;تسمية الملفات&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">التحويل إلى kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">التحويل إلى أحرف صغيرة</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">التحويل إلى حالة الجملة</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">التحويل إلى snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">التحويل إلى حالة العنوان</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">التحويل إلى أحرف كبيرة</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="أدوات-النظام" tabindex="-1">أدوات النظام <a class="header-anchor" href="#أدوات-النظام" aria-label="Permalink to &quot;أدوات النظام&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">منع النظام من النوم</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">اكتشاف بيئة نظام التشغيل</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">تنظيف مساحة القرص القابلة للإزالة</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">تبديل الملفات المخفية في Finder</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">عرض معلومات المضيف</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">عرض إحصائيات استخدام الأوامر</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">سرد الملفات المعدلة مؤخرًا</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">تسجيل خروج عابر للمنصات</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">سرد عمليات المستخدم</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">ساعة إيقاف للطرفية</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">عرض معلومات النظام</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="أوامر-caffeine" tabindex="-1">أوامر Caffeine <a class="header-anchor" href="#أوامر-caffeine" aria-label="Permalink to &quot;أوامر Caffeine&quot;">​</a></h3><p>منع نظامك من النوم أو تفعيل شاشة التوقف.</p><table tabindex="0"><thead><tr><th style="text-align:left;">الأمر</th><th style="text-align:left;">الوصف</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">بدء خدمة caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">التحقق من تشغيل الخدمة</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">إبقاء الشاشة مستيقظة</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">السماح للشاشة بالنوم</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">تبديل يقظة الشاشة</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">إيقاف الخدمة</td></tr></tbody></table><p>يعمل على macOS (باستخدام <code>caffeinate</code> الأصلي) وLinux (<code>xdg-screensaver</code>) وWindows (PowerShell).</p><h3 id="الأمان" tabindex="-1">الأمان <a class="header-anchor" href="#الأمان" aria-label="Permalink to &quot;الأمان&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">توليد كلمات مرور قوية</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">توليد أزواج مفاتيح SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="التنقل" tabindex="-1">التنقل <a class="header-anchor" href="#التنقل" aria-label="Permalink to &quot;التنقل&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">تغيير المجلد وسرد المحتويات</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">تنقل سريع بين المجلدات</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">تركيب للقراءة فقط كقراءة/كتابة</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">حذف مجلد</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">إخراج القرص بأمان</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="متنوعات" tabindex="-1">متنوعات <a class="header-anchor" href="#متنوعات" aria-label="Permalink to &quot;متنوعات&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">الدالة</th><th style="text-align:left;">الوصف</th><th style="text-align:left;">الاستخدام</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">تأثيرات Matrix للطرفية</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">إضافة مجلد إلى PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">فتح في Quick Look على macOS</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">فتح في VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="التوافق" tabindex="-1">التوافق <a class="header-anchor" href="#التوافق" aria-label="Permalink to &quot;التوافق&quot;">​</a></h2><ul><li><strong>macOS</strong> — دعم كامل مع أدوات خاصة بـ macOS</li><li><strong>Linux</strong> — متوافق مع التوزيعات الشائعة</li><li><strong>Windows</strong> — دعم عبر WSL أو Cygwin أو Git Bash</li></ul><h2 id="المساعدة" tabindex="-1">المساعدة <a class="header-anchor" href="#المساعدة" aria-label="Permalink to &quot;المساعدة&quot;">​</a></h2><p>كل دالة تتضمن توثيقًا عبر <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",o]]);export{h as __pageData,y as default};
